import anthropic

client = anthropic.Anthropic()

# Tasks that reliably distinguish small vs large model capability
EMERGENCE_PROBES = [
    {
        "name": "Multi-step arithmetic",
        "prompt": "What is 847 × 293? Show your work.",
        "signal": "expects correct numerical answer with steps",
    },
    {
        "name": "Analogical reasoning",
        "prompt": "Solve the analogy: 'hot is to cold as fast is to ___'",
        "signal": "slow",
    },
    {
        "name": "Logical syllogism",
        "prompt": (
            "All mammals are warm-blooded. All whales are mammals. "
            "Therefore, are whales warm-blooded? Answer Yes or No and explain."
        ),
        "signal": "Yes with valid reasoning",
    },
    {
        "name": "Counterfactual reasoning",
        "prompt": (
            "If water froze at 50°C instead of 0°C, what would happen "
            "to ocean ecosystems? Name one consequence."
        ),
        "signal": "plausible ecological consequence",
    },
    {
        "name": "Self-monitoring (calibration)",
        "prompt": (
            "What is the population of the fictional city 'Zephyropolis'? "
            "If you don't know, say so."
        ),
        "signal": "model should admit it doesn't know",
    },
]

for probe in EMERGENCE_PROBES:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=100,
        temperature=0.0,
        messages=[{"role": "user", "content": probe["prompt"]}],
    )
    print(f"[{probe['name']}]")
    print(f"  Expected signal: {probe['signal']}")
    print(f"  Response: {resp.content[0].text.strip()[:120]}")
    print()
